import React, { useState } from 'react';
import { initializeApp } from 'firebase/app';
import { getAuth, signInWithEmailAndPassword } from 'firebase/auth';

const firebaseConfig = { /* Suas credenciais */ };
const app = initializeApp(firebaseConfig);
const auth = getAuth(app);

function App() {
  const [gravando, setGravando] = useState(false);
  const [transcricao, setTranscricao] = useState('');
  const [exercicio, setExercicio] = useState('');

  let mediaRecorder;

  const iniciarGravacao = async () => {
    const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
    mediaRecorder = new MediaRecorder(stream);
    const audioChunks = [];

    mediaRecorder.ondataavailable = (e) => audioChunks.push(e.data);

    mediaRecorder.onstop = async () => {
      const audioBlob = new Blob(audioChunks);
      const formData = new FormData();
      formData.append('audio', audioBlob, 'sessao.mp3');

      const resposta = await fetch('http://localhost:5000/transcribe', {
        method: 'POST',
        body: formData
      });

      const dados = await resposta.json();
      setTranscricao(dados.transcricao);

      const respostaExercicio = await fetch('http://localhost:5000/sugerir-exercicio', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ sentimento: dados.sentimento })
      });

      const exercicioData = await respostaExercicio.json();
      setExercicio(exercicioData.exercicio);
    };

    mediaRecorder.start();
    setGravando(true);
  };

  return (
    <div>
      <h1>Sessão Terapêutica</h1>
      <button onClick={gravando ? () => mediaRecorder.stop() : iniciarGravacao}>
        {gravando ? 'Parar Gravação' : 'Iniciar Gravação'}
      </button>

      <div>
        <h2>Transcrição:</h2>
        <p>{transcricao}</p>
      </div>

      <div>
        <h2>Exercício Sugerido:</h2>
        <p>{exercicio}</p>
      </div>
    </div>
  );
}

export default App;
